#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use URI::Escape;

my $cgi = CGI->new;
my $next_param = $cgi->param('next');

my $redirect_url = '';

if ($next_param) {
    # Validate that the redirect URL is from our domain or a trusted domain
    if ($next_param =~ m!^https?://(www\.)?yourdomain\.com/! || $next_param =~ m!^/!) {
        $redirect_url = $next_param;
    } else {
        # Fallback to home page if invalid redirect URL
        $redirect_url = '/';
    }
} else {
    # Default redirect if no next parameter
    $redirect_url = '/';
}

# URL encode the redirect URL
$redirect_url = uri_escape($redirect_url);

print $cgi->redirect($redirect_url);
exit;